import { useEffect, useState } from "react";
import "./CompanyPendingBugs.scss";

export default function CompanyPendingBugs() {
  const [bugs, setBugs] = useState([]);
  const token = localStorage.getItem("token");

  useEffect(() => {
    fetch("http://localhost:5000/api/bugs/company/bugs", {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then(res => res.json())
      .then(data =>
        setBugs((data.bugs || []).filter(b => b.status === "submitted"))
      );
  }, [token]);

  return (
    <div className="company-page">
      <h1>🐞 New Bugs</h1>

      {bugs.map(bug => (
        <div className="bug-card" key={bug._id}>
          <h3>{bug.title}</h3>
          <div className="bug-id">ID: {bug._id}</div>
          <p>{bug.description}</p>

          <div className="actions">
            <button>Approve</button>
            <button>Reject</button>
            <button>Duplicate</button>
          </div>
        </div>
      ))}
    </div>
  );
}
